import React, { Component } from 'react';
import './Btn.css';

class Btn extends Component {
    render() {
        const {
            title,
            link
        } = this.props;

        const openWindow = () => {
            window.open(link, '_blank');
        }

        return (
            <p>tmp</p>
        )

        return (
            <button className="Btn" onClick="openWindow()">
                <div className="Btn-title">{title}</div>
            </button>
        );
    }
}

export default Btn;
